"use client"

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"
import { cn } from "@/lib/utils"
import { type ActiveMsg, type Flash, drawFrame, setupCanvas } from "./mn-network-messages.helpers"

/* ── CVA wrapper ───────────────────────────────────────────── */
const networkWrap = cva("relative overflow-hidden", {
  variants: { size: { sm: "", md: "", lg: "", fluid: "h-full w-full" } },
  defaultVariants: { size: "fluid" },
})
type WrapSize = NonNullable<VariantProps<typeof networkWrap>["size"]>

/* ── Public types ──────────────────────────────────────────── */
export interface NetNode {
  id: string; label: string; x: number; y: number
  color?: string; size?: number
}
export interface NetMessage {
  from: string; to: string; color?: string
  speed?: number; size?: number; label?: string
}
export interface NetConnection { from: string; to: string; color?: string }
export interface NetworkMessagesController {
  send: (msg: NetMessage) => void
  burst: (msgs: NetMessage[]) => void
}

export interface MnNetworkMessagesProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "children">,
    VariantProps<typeof networkWrap> {
  nodes: NetNode[]
  connections: NetConnection[]
  width?: number
  height?: number
  particleTrail?: boolean
  glowEffect?: boolean
  onNodeClick?: (node: NetNode) => void
  controllerRef?: { current: NetworkMessagesController | null }
  /** Default node fill color (hex). */
  nodeColor?: string
  /** Accent / gradient-end color (hex). */
  accentColor?: string
  /** Node label color (hex or rgba). */
  labelColor?: string
  /** Canvas background overlay. */
  bgOverlay?: string
}

/* ── Component ─────────────────────────────────────────────── */
function MnNetworkMessages({
  nodes, connections, width, height,
  particleTrail = true, glowEffect = true,
  onNodeClick, controllerRef,
  nodeColor = "#4EA8DE", accentColor = "#FFC72C",
  labelColor = "#f5f1e6", bgOverlay = "rgba(3,7,12,0.36)",
  size = "fluid", className, ...rest
}: MnNetworkMessagesProps) {
  const cvs = React.useRef<HTMLCanvasElement>(null)
  const wrap = React.useRef<HTMLDivElement>(null)
  const raf = React.useRef(0)
  const msgsRef = React.useRef<ActiveMsg[]>([])
  const flashesRef = React.useRef<Flash[]>([])
  const lastTs = React.useRef(0)

  const send = React.useCallback((msg: NetMessage) => {
    const map = new Map(nodes.map((n) => [n.id, n]))
    if (!map.get(msg.from) || !map.get(msg.to)) return
    msgsRef.current.push({
      ...msg, progress: 0,
      speed: Math.max(0.5, Math.min(3, msg.speed ?? 1)),
      size: msg.size ?? 4, trail: [],
    })
  }, [nodes])

  const burst = React.useCallback(
    (m: NetMessage[]) => m.forEach(send),
    [send],
  )

  React.useEffect(() => {
    if (controllerRef) controllerRef.current = { send, burst }
    return () => { if (controllerRef) controllerRef.current = null }
  }, [controllerRef, send, burst])

  React.useEffect(() => {
    const canvas = cvs.current, host = wrap.current
    if (!canvas || !host) return
    const ctx = canvas.getContext("2d")
    if (!ctx) return

    const resize = () => {
      const w = width ?? Math.max(320, host.clientWidth || 640)
      const h = height ?? Math.max(220, host.clientHeight || 320)
      setupCanvas(canvas, w, h)
    }

    const loop = (now: number) => {
      const dt = Math.min(48, lastTs.current ? now - lastTs.current : 16)
      lastTs.current = now
      drawFrame(
        ctx, canvas.clientWidth || 1, canvas.clientHeight || 1, dt,
        nodes, connections, msgsRef.current, flashesRef.current,
        { trail: particleTrail, glow: glowEffect, nodeColor, accent: accentColor, label: labelColor, bg: bgOverlay },
      )
      raf.current = requestAnimationFrame(loop)
    }

    resize()
    raf.current = requestAnimationFrame(loop)
    const ro = typeof ResizeObserver !== "undefined" ? new ResizeObserver(resize) : null
    ro?.observe(host)
    return () => { cancelAnimationFrame(raf.current); ro?.disconnect() }
  }, [nodes, connections, particleTrail, glowEffect, width, height, nodeColor, accentColor, labelColor, bgOverlay])

  const handleClick = React.useCallback(
    (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (!onNodeClick || !cvs.current) return
      const rect = cvs.current.getBoundingClientRect()
      const mx = e.clientX - rect.left, my = e.clientY - rect.top
      const w = cvs.current.clientWidth, h = cvs.current.clientHeight
      for (let i = nodes.length - 1; i >= 0; i--) {
        const n = nodes[i]
        if (Math.hypot(mx - n.x * w, my - n.y * h) <= (n.size ?? 10) + 3) {
          onNodeClick(n); return
        }
      }
    },
    [nodes, onNodeClick],
  )

  return (
    <div
      ref={wrap} role="img" aria-label="Network message flow"
      className={cn(networkWrap({ size: size as WrapSize }), className)}
      {...rest}
    >
      <canvas ref={cvs} className="block w-full h-full" onClick={handleClick} tabIndex={0} />
    </div>
  )
}

export { MnNetworkMessages, networkWrap }

import type { NetNode, NetConnection, NetMessage } from "./mn-network-messages"

/* ── Internal types ────────────────────────────────────────── */
export type ActiveMsg = NetMessage & {
  progress: number; speed: number; size: number
  trail: { x: number; y: number }[]
}
export type Flash = {
  x: number; y: number; radius: number; life: number; color: string
}
export interface DrawOpts {
  trail: boolean; glow: boolean
  nodeColor: string; accent: string; label: string; bg: string
}

/* ── Helpers ───────────────────────────────────────────────── */
export function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * t
}

export function colorAlpha(color: string, opacity: number): string {
  if (color.startsWith("rgba(")) return color.replace(/[\d.]+\)$/, `${opacity})`)
  if (color.startsWith("rgb(")) return color.replace("rgb(", "rgba(").replace(")", `,${opacity})`)
  const hex = color.replace("#", "")
  const full = hex.length === 3 ? hex.replace(/./g, "$&$&") : hex
  const v = parseInt(full, 16)
  if (Number.isNaN(v)) return `rgba(78,168,222,${opacity})`
  return `rgba(${(v >> 16) & 255},${(v >> 8) & 255},${v & 255},${opacity})`
}

export function setupCanvas(cvs: HTMLCanvasElement, w: number, h: number): void {
  const dpr = window.devicePixelRatio || 1
  cvs.width = w * dpr; cvs.height = h * dpr
  cvs.style.width = `${w}px`; cvs.style.height = `${h}px`
  cvs.getContext("2d")?.scale(dpr, dpr)
}

function drawParticle(
  ctx: CanvasRenderingContext2D, color: string,
  x: number, y: number, r: number, glow: boolean, label?: string,
): void {
  ctx.save()
  if (glow) { ctx.shadowColor = color; ctx.shadowBlur = r * 3 }
  ctx.fillStyle = color; ctx.beginPath(); ctx.arc(x, y, Math.max(0, r), 0, Math.PI * 2); ctx.fill()
  if (label) {
    ctx.shadowBlur = 0; ctx.fillStyle = "#05070c"
    ctx.font = `600 ${Math.max(9, r * 2.1)}px Inter,sans-serif`
    ctx.textAlign = "center"; ctx.textBaseline = "middle"
    ctx.fillText(label.slice(0, 3), x, y + 0.5)
  }
  ctx.restore()
}

/* ── Frame renderer ────────────────────────────────────────── */
export function drawFrame(
  ctx: CanvasRenderingContext2D, w: number, h: number, dt: number,
  nodes: NetNode[], conns: NetConnection[],
  msgs: ActiveMsg[], flashes: Flash[], o: DrawOpts,
): void {
  const map = new Map(nodes.map((n) => [n.id, n]))
  const pt = (n: NetNode) => ({ x: n.x * w, y: n.y * h })

  ctx.clearRect(0, 0, w, h)
  ctx.fillStyle = o.bg; ctx.fillRect(0, 0, w, h)

  // ── Edges
  for (const link of conns) {
    const f = map.get(link.from), t = map.get(link.to)
    if (!f || !t) continue
    const a = pt(f), b = pt(t)
    const active = msgs.some((m) => m.from === link.from && m.to === link.to)
    const mx = (a.x + b.x) / 2, my = (a.y + b.y) / 2
    const dx = mx - w / 2, dy = my - h / 2, len = Math.hypot(dx, dy) || 1
    const dist = Math.hypot(b.x - a.x, b.y - a.y)
    const op = active ? 0.7 : 0.38
    ctx.save(); ctx.lineWidth = active ? 2 : 1.5
    if (active && o.glow) { ctx.shadowColor = link.color ?? o.nodeColor; ctx.shadowBlur = 8 }
    if (link.color) {
      ctx.strokeStyle = colorAlpha(link.color, op)
    } else {
      const grad = ctx.createLinearGradient(a.x, a.y, b.x, b.y)
      grad.addColorStop(0, colorAlpha(o.nodeColor, op))
      grad.addColorStop(1, colorAlpha(o.accent, op))
      ctx.strokeStyle = grad
    }
    ctx.beginPath(); ctx.moveTo(a.x, a.y)
    ctx.quadraticCurveTo(mx + (dx / len) * dist * 0.28, my + (dy / len) * dist * 0.28, b.x, b.y)
    ctx.stroke(); ctx.restore()
  }

  // ── Flashes
  for (let i = flashes.length - 1; i >= 0; i--) {
    const fl = flashes[i]
    fl.life -= dt * 0.0026; fl.radius += dt * 0.05
    if (fl.life <= 0) { flashes.splice(i, 1); continue }
    ctx.save()
    ctx.strokeStyle = colorAlpha(fl.color, fl.life * 0.75)
    ctx.lineWidth = 1.5 + fl.life * 2
    if (o.glow) { ctx.shadowColor = fl.color; ctx.shadowBlur = 10 * fl.life }
    ctx.beginPath(); ctx.arc(fl.x, fl.y, Math.max(0, fl.radius), 0, Math.PI * 2); ctx.stroke()
    ctx.restore()
  }

  // ── Active messages
  for (let i = msgs.length - 1; i >= 0; i--) {
    const m = msgs[i]
    const from = map.get(m.from), to = map.get(m.to)
    if (!from || !to) { msgs.splice(i, 1); continue }
    m.progress += (dt / 1500) * m.speed
    const a = pt(from), b = pt(to)
    const x = lerp(a.x, b.x, m.progress), y = lerp(a.y, b.y, m.progress)
    const c = m.color ?? to.color ?? o.accent
    if (o.trail) {
      m.trail.push({ x, y }); if (m.trail.length > 10) m.trail.shift()
      m.trail.forEach((p, idx) => {
        const r = m.size * (0.35 + idx / 18)
        drawParticle(ctx, c, p.x, p.y, r, o.glow)
        ctx.save(); ctx.globalAlpha = ((idx + 1) / m.trail.length) * 0.18
        ctx.fillStyle = c; ctx.beginPath(); ctx.arc(p.x, p.y, r, 0, Math.PI * 2); ctx.fill()
        ctx.restore()
      })
    }
    if (m.progress >= 1) {
      flashes.push({ x: b.x, y: b.y, radius: 4, life: 1, color: c })
      msgs.splice(i, 1); continue
    }
    drawParticle(ctx, c, x, y, m.size, o.glow, m.label)
  }

  // ── Nodes
  for (const node of nodes) {
    const p = pt(node), s = node.size ?? 10, c = node.color ?? o.nodeColor
    ctx.save()
    if (o.glow) { ctx.shadowColor = c; ctx.shadowBlur = s * 1.4 }
    ctx.fillStyle = colorAlpha(c, 0.2)
    ctx.beginPath(); ctx.arc(p.x, p.y, s * 1.7, 0, Math.PI * 2); ctx.fill()
    ctx.fillStyle = c
    ctx.beginPath(); ctx.arc(p.x, p.y, s, 0, Math.PI * 2); ctx.fill()
    ctx.restore()
    ctx.fillStyle = o.label; ctx.font = "600 12px Inter,sans-serif"
    ctx.textAlign = "center"
    ctx.fillText(node.label, p.x, p.y + s + 18)
  }
}
